import {pool} from '../infra/pg';
import {io} from '../server';
export async function moveCard(cardId:number,toColumnId:number,newPosition:number,boardId:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock($1)',[toColumnId]);
    const wip=await client.query('SELECT wip_limit, (SELECT count(*) FROM cards WHERE column_id=$1) AS n FROM columns WHERE id=$1',[toColumnId]);
    const fromCol=(await client.query('SELECT column_id FROM cards WHERE id=$1',[cardId])).rows[0]?.column_id;
    if(wip.rows[0].wip_limit&&Number(wip.rows[0].n)>=Number(wip.rows[0].wip_limit)&&Number(fromCol)!==toColumnId){await client.query('ROLLBACK');return {error:'wip_exceeded'};}
    await client.query('UPDATE cards SET column_id=$1,position=$2,version=version+1 WHERE id=$3',[toColumnId,newPosition,cardId]);
    await client.query('COMMIT');
    io.of('/board').to(`board:${boardId}`).emit('card:moved',{cardId:String(cardId),toColumnId:String(toColumnId),newPosition});
    return {ok:true};
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
export function registerBoardNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    socket.on('board:open',async({boardId}:any,ack:any)=>{await socket.join(`board:${boardId}`);const c=await pool.query('SELECT * FROM columns WHERE board_id=$1 ORDER BY position',[boardId]);const cards=await pool.query('SELECT * FROM cards WHERE column_id=ANY($1::bigint[]) ORDER BY column_id,position',[c.rows.map(x=>x.id)]);ack({columns:c.rows,cards:cards.rows});});
    socket.on('card:moving',({boardId,cardId,toColumnId,newPosition}:any)=>{socket.to(`board:${boardId}`).emit('card:moving',{cardId,toColumnId,newPosition});});
    socket.on('card:move',async({boardId,cardId,toColumnId,newPosition}:any,ack:any)=>{ack(await moveCard(cardId,toColumnId,newPosition,boardId));});
  });
}

