import DOMPurify from 'isomorphic-dompurify';
import {marked} from 'marked';
import hljs from 'highlight.js';
import crypto from 'crypto';
async function renderMd(md:string):Promise<string>{
  const html=await marked.parse(md,{async:true,gfm:true});
  // highlight code
  const out=html.replace(/<pre><code class="language-(\w+)">([\s\S]*?)<\/code><\/pre>/g,(_:string,lang:string,code:string)=>{
    const hash=crypto.createHash('sha1').update(lang+code).digest('hex');
    try{const h=hljs.highlight(code,{language:lang}).value;return `<pre><code class="language-${lang} hljs">${h}</code></pre>`;}catch{return _;}
  });
  return DOMPurify.sanitize(out);
}
