import {PictRoom} from '../models/PictRoom';
import {io} from '../server';
function norm(s:string){return s.toLowerCase().replace(/\s+/g,'').trim();}
export function registerPictNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=String(socket.data.user.id);
    socket.on('room:join',async({roomId}:any,ack:any)=>{await socket.join(`room:${roomId}`);const r=await PictRoom.findById(roomId).lean();ack({room:r,word:r?.currentRound?.drawerId===uid?r.currentRound.word:r?.currentRound?.wordMasked});});
    socket.on('stroke',({roomId,stroke}:any)=>{socket.to(`room:${roomId}`).emit('stroke:peer',stroke);});
    socket.on('guess',async({roomId,text}:any,ack:any)=>{
      const r=await PictRoom.findOne({_id:roomId},{currentRound:1});if(!r||!r.currentRound||r.currentRound.winnerId)return ack({error:'no_round'});
      if(r.currentRound.drawerId===uid)return ack({error:'drawer_cant_guess'});
      const correct=norm(text)===norm(r.currentRound.word);
      if(correct){const upd=await PictRoom.findOneAndUpdate({_id:roomId,'currentRound.winnerId':null},{$set:{'currentRound.winnerId':uid}},{new:true});if(upd?.currentRound?.winnerId===uid)io.of('/pict').to(`room:${roomId}`).emit('winner',{userId:uid,word:r.currentRound.word});}
      io.of('/pict').to(`room:${roomId}`).emit('guess:peer',{userId:uid,text,correct});
      ack({ok:true,correct});
    });
  });
}

