import {pool} from '../infra/pg';
import {io} from '../server';
import crypto from 'crypto';
function verifyCommit(amount:number,nonce:string,commit:string){return crypto.createHash('sha256').update(`${amount}|${nonce}`).digest('hex')===commit;}
export function registerSealedNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=socket.data.user.id;
    socket.on('auction:watch',async({auctionId}:any,ack:any)=>{await socket.join(`auction:${auctionId}`);const a=await pool.query('SELECT * FROM sealed_auctions WHERE id=$1',[auctionId]);ack({auction:a.rows[0]});});
    socket.on('bid:commit',async({auctionId,commitment}:any,ack:any)=>{const a=await pool.query('SELECT closes_at FROM sealed_auctions WHERE id=$1',[auctionId]);if(!a.rows[0]||new Date(a.rows[0].closes_at).getTime()<Date.now())return ack({error:'closed'});await pool.query('INSERT INTO sealed_bids(auction_id,bidder_id,commitment) VALUES ($1,$2,$3) ON CONFLICT (auction_id,bidder_id) DO UPDATE SET commitment=EXCLUDED.commitment',[auctionId,uid,commitment]);ack({ok:true});});
    socket.on('bid:reveal',async({auctionId,amountCents,nonce}:any,ack:any)=>{const b=await pool.query('SELECT commitment FROM sealed_bids WHERE auction_id=$1 AND bidder_id=$2',[auctionId,uid]);if(!b.rows[0])return ack({error:'no_commitment'});if(!verifyCommit(amountCents,nonce,b.rows[0].commitment))return ack({error:'mismatch'});await pool.query('UPDATE sealed_bids SET amount_cents=$1,nonce=$2,revealed_at=now() WHERE auction_id=$3 AND bidder_id=$4',[amountCents,nonce,auctionId,uid]);ack({ok:true});});
  });
}
// after reveals_at, settle:
export async function settle(auctionId:number){
  const r=await pool.query('SELECT bidder_id,amount_cents FROM sealed_bids WHERE auction_id=$1 AND amount_cents IS NOT NULL ORDER BY amount_cents DESC LIMIT 2',[auctionId]);
  if(r.rows.length===0)return;
  const winner=r.rows[0].bidder_id;const second=r.rows[1]?.amount_cents??r.rows[0].amount_cents;
  await pool.query("UPDATE sealed_auctions SET winner_id=$1,second_price_cents=$2,status='settled' WHERE id=$3",[winner,second,auctionId]);
  io.of('/sealed').to(`auction:${auctionId}`).emit('state',{status:'settled',winner:String(winner),paidCents:Number(second)});
}

