import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
import crypto from 'crypto';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/sealed',{auth:{token:t},transports:['websocket']});return sock;}
export function useSealed(auctionId:string,token:string){
  const [auction,setA]=useState<any>(null);
  useEffect(()=>{const s=getSock(token);s.emit('auction:watch',{auctionId},(r:any)=>setA(r.auction));const onS=(e:any)=>setA((a:any)=>({...a,...e}));s.on('state',onS);return ()=>{s.off('state',onS);};},[auctionId,token]);
  const commit=useCallback((amountCents:number)=>{const nonce=crypto.randomBytes(16).toString('hex');const commitment=crypto.createHash('sha256').update(`${amountCents}|${nonce}`).digest('hex');localStorage.setItem(`seal:${auctionId}`,JSON.stringify({amountCents,nonce}));return new Promise((res,rej)=>getSock(token).emit('bid:commit',{auctionId,commitment},(r:any)=>r.error?rej(r):res(r)));},[auctionId,token]);
  const reveal=useCallback(()=>{const stored=JSON.parse(localStorage.getItem(`seal:${auctionId}`)||'{}');if(!stored.nonce)return Promise.reject('no_stored');return new Promise((res,rej)=>getSock(token).emit('bid:reveal',{auctionId,...stored},(r:any)=>r.error?rej(r):res(r)));},[auctionId,token]);
  return {auction,commit,reveal};
}

