import {io} from '../server';
export async function setPhase(intersectionId:number,phase:string,reason:string){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const cur=await client.query('SELECT current_phase,phase_started_at FROM intersections WHERE id=$1 FOR UPDATE',[intersectionId]);
    if(cur.rows[0].current_phase===phase){await client.query('ROLLBACK');return;}
    await client.query('INSERT INTO phase_log(intersection_id,phase,started_at,ended_at,reason) VALUES ($1,$2,$3,now(),$4)',[intersectionId,cur.rows[0].current_phase,cur.rows[0].phase_started_at,reason]);
    await client.query('UPDATE intersections SET current_phase=$1,phase_started_at=now() WHERE id=$2',[phase,intersectionId]);
    await client.query('COMMIT');
    io.of('/traffic').to(`int:${intersectionId}`).emit('phase:change',{intersectionId:String(intersectionId),phase});
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
