import {pool} from '../infra/pg';
import {io} from '../server';
export async function popNext(tutorId:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const r=await client.query(`SELECT id,student_id FROM office_queue WHERE tutor_id=$1 AND status='waiting' ORDER BY joined_at LIMIT 1 FOR UPDATE SKIP LOCKED`,[tutorId]);
    if(r.rowCount===0){await client.query('ROLLBACK');return null;}
    await client.query(`UPDATE office_queue SET status='active' WHERE id=$1`,[r.rows[0].id]);
    await client.query('COMMIT');
    io.of('/office').to(`user:${r.rows[0].student_id}`).emit('student:popped',{tutorId:String(tutorId)});
    return r.rows[0];
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
export function registerOfficeNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=socket.data.user.id;socket.join(`user:${uid}`);
    if(socket.data.user.role==='tutor')socket.join(`tutor:${uid}`);
    socket.on('student:queue',async({tutorId}:any,ack:any)=>{const r=await pool.query('INSERT INTO office_queue(tutor_id,student_id) VALUES ($1,$2) RETURNING id',[tutorId,uid]);io.of('/office').to(`tutor:${tutorId}`).emit('queue:state',{action:'add',studentId:String(uid)});ack({queueId:String(r.rows[0].id)});});
    socket.on('student:cancel',async({queueId}:any,ack:any)=>{await pool.query("UPDATE office_queue SET status='cancelled' WHERE id=$1 AND student_id=$2",[queueId,uid]);ack({ok:true});});
    socket.on('tutor:pop',async({tutorId}:any,ack:any)=>{if(Number(uid)!==Number(tutorId))return ack({error:'forbidden'});const r=await popNext(Number(tutorId));ack({popped:r});});
  });
}

