    socket.on('doc:open',async({docId}:any,ack:any)=>{await socket.join(`doc:${docId}`);const c=await PrdComment.find({docId,resolved:false}).lean();ack({comments:c});});
    socket.on('comment:add',async({docId,sectionId,body}:any,ack:any)=>{const c=await PrdComment.create({_id:uuid(),docId,sectionId,authorId:uid,body,replies:[],createdAt:new Date()});io.of('/prd').to(`doc:${docId}`).emit('comment:new',c.toObject());for(const m of (body.match(/@(\d+)/g)||[])){const mid=m.slice(1);await enqueueNotification(mid,{type:'prd_mention',targetType:'comment',targetId:String(c._id),actorId:uid,body:`Mentioned in PRD`});}ack({comment:c.toObject()});});
    socket.on('reply',async({commentId,body}:any,ack:any)=>{const c=await PrdComment.findByIdAndUpdate(commentId,{$push:{replies:{authorId:uid,body,at:new Date()}}},{new:true});io.of('/prd').to(`doc:${c?.docId}`).emit('comment:reply',{commentId,reply:{authorId:uid,body,at:new Date()}});ack({ok:true});});
