import {pool} from '../infra/pg';
import {io} from '../server';
import {redis,sub} from '../infra/redis';
// Quote worker writes to redis pub/sub channel 'quote:tick'
export function startPfNamespace(nsp:any){
  nsp.use(authMw);
  const userSubs=new Map<string,Set<string>>(); // userId → symbols
  sub.subscribe('quote:tick');
  sub.on('message',async(_ch,payload)=>{const {symbol,price}=JSON.parse(payload);for(const [uid,syms] of userSubs){if(syms.has(symbol)){const h=await pool.query('SELECT qty,cost_basis_cents FROM holdings WHERE user_id=$1 AND symbol=$2',[uid,symbol]);if(h.rows[0]){const pnl=Number(h.rows[0].qty)*price-Number(h.rows[0].cost_basis_cents);io.of('/pf').to(`user:${uid}`).emit('tick',{symbol,price,pnl});}}}});
  nsp.on('connection',(socket:any)=>{
    const uid=String(socket.data.user.id);socket.join(`user:${uid}`);
    socket.on('pf:subscribe',async(_:any,ack:any)=>{const r=await pool.query('SELECT symbol,qty,cost_basis_cents FROM holdings WHERE user_id=$1',[uid]);userSubs.set(uid,new Set(r.rows.map(x=>x.symbol)));ack({holdings:r.rows});});
    socket.on('disconnect',()=>userSubs.delete(uid));
  });
}

