import {io} from '../server';
export async function action(tableId:number,userId:number,kind:string,amount?:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const t=await client.query('SELECT seats,current_hand_id FROM poker_tables WHERE id=$1 FOR UPDATE',[tableId]);
    const h=await client.query('SELECT current_seat,deadline,pot_cents FROM hands WHERE id=$1 FOR UPDATE',[t.rows[0].current_hand_id]);
    const expectedSeat=t.rows[0].seats[h.rows[0].current_seat];
    if(expectedSeat!==userId){await client.query('ROLLBACK');return {error:'not_your_turn'};}
    // apply action (simplified)
    const newPot=h.rows[0].pot_cents+(amount||0);
    const nextSeat=(h.rows[0].current_seat+1)%6;
    await client.query('UPDATE hands SET pot_cents=$1,current_seat=$2,deadline=now()+interval \'30 seconds\', actions=actions || $3::jsonb WHERE id=$4',[newPot,nextSeat,JSON.stringify([{userId,kind,amount}]),t.rows[0].current_hand_id]);
    await client.query('COMMIT');
    io.of('/poker').to(`table:${tableId}`).emit('public:state',{tableId:String(tableId),pot:newPot,currentSeat:nextSeat,lastAction:{userId,kind,amount}});
    return {ok:true};
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
