import {Party} from '../models/Party';
import {io} from '../server';
export function registerPartyNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=String(socket.data.user.id);
    socket.on('party:join',async({partyId}:any,ack:any)=>{await socket.join(`party:${partyId}`);const p=await Party.findById(partyId).lean();if(!p)return ack({error:'no_party'});// drift compensate: if playing, advance by elapsed
      const drift=p.playing?(Date.now()-new Date(p.updatedAt).getTime())/1000:0;
      ack({party:{...p,currentTime:p.currentTime+drift}});});
    socket.on('play',async({partyId,currentTime}:any,ack:any)=>{const p=await Party.findById(partyId);if(!p||p.hostId!==uid)return ack({error:'not_host'});p.currentTime=currentTime;p.playing=true;p.updatedAt=new Date();await p.save();io.of('/party').to(`party:${partyId}`).emit('state',{playing:true,currentTime,ts:Date.now()});ack({ok:true});});
    socket.on('pause',async({partyId,currentTime}:any,ack:any)=>{const p=await Party.findById(partyId);if(!p||p.hostId!==uid)return ack({error:'not_host'});p.currentTime=currentTime;p.playing=false;p.updatedAt=new Date();await p.save();io.of('/party').to(`party:${partyId}`).emit('state',{playing:false,currentTime,ts:Date.now()});ack({ok:true});});
    socket.on('seek',async({partyId,currentTime}:any,ack:any)=>{const p=await Party.findById(partyId);if(!p||p.hostId!==uid)return ack({error:'not_host'});p.currentTime=currentTime;p.updatedAt=new Date();await p.save();io.of('/party').to(`party:${partyId}`).emit('state',{playing:p.playing,currentTime,ts:Date.now()});ack({ok:true});});
    socket.on('chat',({partyId,body}:any)=>{io.of('/party').to(`party:${partyId}`).emit('chat',{userId:uid,body,ts:Date.now()});});
  });
