const jQ=new Queue('journey',{connection:redis});
export async function enrollJourney(userId:number,journeyId:number){await pool.query('INSERT INTO journey_state(user_id,journey_id,current_step,started_at) VALUES ($1,$2,0,now()) ON CONFLICT DO NOTHING',[userId,journeyId]);await jQ.add('step',{userId,journeyId});}
export function startJourneyWorker(){
  new Worker('journey',async(job:any)=>{
    const {userId,journeyId}=job.data;
    const s=(await pool.query('SELECT current_step,paused,unsubscribed FROM journey_state WHERE user_id=$1 AND journey_id=$2',[userId,journeyId])).rows[0];
    if(!s||s.paused||s.unsubscribed)return;
    const j=(await pool.query('SELECT steps FROM journeys WHERE id=$1',[journeyId])).rows[0];
    const step=j.steps[s.current_step];if(!step)return;
    // execute step (email/sms/in-app)
    await dispatchStep(userId,step);
    await pool.query(`INSERT INTO journey_history(user_id,journey_id,step,action) VALUES ($1,$2,$3,$4)`,[userId,journeyId,s.current_step,step.action]);
    await pool.query('UPDATE journey_state SET current_step=current_step+1 WHERE user_id=$1 AND journey_id=$2',[userId,journeyId]);
    io.of('/journey').to(`user:${userId}`).emit('step:executed',{journeyId:String(journeyId),step:s.current_step});
    if(s.current_step+1<j.steps.length){const next=j.steps[s.current_step+1];await jQ.add('step',{userId,journeyId},{delay:next.delayMs||0});}
  },{connection:redis});
}
async function dispatchStep(...args:any[]){/* email/sms/inApp */}
