export async function popNext(clinicId:number,doctorId:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const r=await client.query(`SELECT id,patient_id FROM telehealth_queue WHERE clinic_id=$1 AND status='waiting' ORDER BY priority ASC, joined_at ASC LIMIT 1 FOR UPDATE SKIP LOCKED`,[clinicId]);
    if(r.rowCount===0){await client.query('ROLLBACK');return null;}
    await client.query(`UPDATE telehealth_queue SET status='active',popped_by=$1,popped_at=now() WHERE id=$2`,[doctorId,r.rows[0].id]);
    await client.query('COMMIT');
    io.of('/tele').to(`clinic:${clinicId}`).emit('queue:state',{action:'popped',entryId:String(r.rows[0].id)});
    return r.rows[0];
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
export function registerTeleNamespace(nsp:any){
