    const uid=socket.data.user.id;
    socket.on('queue:join',async({clinicId}:any,ack:any)=>{const r=await pool.query('INSERT INTO telehealth_queue(clinic_id,patient_id,status) VALUES ($1,$2,$3) RETURNING id',[clinicId,uid,'waiting']);await socket.join(`clinic:${clinicId}`);io.of('/tele').to(`clinic:${clinicId}`).emit('queue:state',{action:'added',entryId:String(r.rows[0].id)});ack({entryId:String(r.rows[0].id)});});
