import {pool} from '../infra/pg';
import {io} from '../server';
export async function sign(itemId:number,userId:number,role:string){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const i=await client.query('SELECT prep_sign_at,rev_sign_at,app_sign_at,audit_id FROM audit_items WHERE id=$1 FOR UPDATE',[itemId]);
    if(role==='preparer'&&i.rows[0].prep_sign_at){await client.query('ROLLBACK');return {error:'already_signed'};}
    if(role==='reviewer'&&(!i.rows[0].prep_sign_at||i.rows[0].rev_sign_at)){await client.query('ROLLBACK');return {error:'sequence_violation'};}
    if(role==='approver'&&(!i.rows[0].rev_sign_at||i.rows[0].app_sign_at)){await client.query('ROLLBACK');return {error:'sequence_violation'};}
    const col=role==='preparer'?'prep':role==='reviewer'?'rev':'app';
    await client.query(`UPDATE audit_items SET ${col}_sign_by=$1, ${col}_sign_at=now() WHERE id=$2`,[userId,itemId]);
    await client.query(`INSERT INTO audit_log(audit_id,item_id,actor_id,action) VALUES ($1,$2,$3,$4)`,[i.rows[0].audit_id,itemId,userId,`sign_${role}`]);
    await client.query('COMMIT');
    io.of('/sox').to(`audit:${i.rows[0].audit_id}`).emit('item:updated',{itemId:String(itemId),role,signedBy:String(userId)});
    return {ok:true};
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
export function registerSoxNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    socket.on('audit:open',async({auditId}:any,ack:any)=>{await socket.join(`audit:${auditId}`);const i=await pool.query('SELECT * FROM audit_items WHERE audit_id=$1',[auditId]);ack({items:i.rows});});
    socket.on('item:sign',async({itemId,role}:any,ack:any)=>{const r=await sign(itemId,socket.data.user.id,role);ack(r);});
  });
}

