import {Report} from '../models/Report';
import {Queue,Worker} from 'bullmq';
import {redis} from '../infra/redis';
import {io} from '../server';
import crypto from 'crypto';
const rQ=new Queue('compreport',{connection:redis});
export async function startReport(userId:number,params:any){
  const hash=crypto.createHash('sha256').update(JSON.stringify(params)).digest('hex');
  const existing=await Report.findOne({paramsHash:hash,status:'done'});
  if(existing)return {reportId:String(existing._id),cached:true,storageKey:existing.storageKey};
  const r=await Report.create({_id:`r_${Date.now()}`,paramsHash:hash,status:'pending',pages:0,rendered:0});
  await rQ.add('gen',{reportId:String(r._id),params});
  return {reportId:String(r._id),cached:false};
}
export function startReportWorker(){
  new Worker('compreport',async(job:any)=>{
    const {reportId,params}=job.data;
    const totalPages=100;
    await Report.updateOne({_id:reportId},{$set:{status:'running',pages:totalPages}});
    for(let i=0;i<totalPages;i++){
      const cancelled=await redis.get(`rep:cancel:${reportId}`);
      if(cancelled){await Report.updateOne({_id:reportId},{$set:{status:'cancelled'}});io.of('/compreport').to(`report:${reportId}`).emit('done',{status:'cancelled'});return;}
      await new Promise(r=>setTimeout(r,50)); // render page
      await Report.updateOne({_id:reportId},{$inc:{rendered:1}});
      io.of('/compreport').to(`report:${reportId}`).emit('progress',{reportId,rendered:i+1,total:totalPages});
    }
    const key=`reports/${reportId}.pdf`;
    await Report.updateOne({_id:reportId},{$set:{status:'done',storageKey:key}});
    io.of('/compreport').to(`report:${reportId}`).emit('done',{status:'done',storageKey:key});
  },{connection:redis});
}
export function registerReportNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    socket.on('report:subscribe',async({reportId}:any,ack:any)=>{await socket.join(`report:${reportId}`);const r=await Report.findById(reportId).lean();ack({report:r});});
    socket.on('report:cancel',async({reportId}:any)=>{await redis.set(`rep:cancel:${reportId}`,'1','EX',300);});
  });
}

